import { AutkSpatialDb } from 'autk-db';

const URL = 'https://raw.githubusercontent.com/urban-toolkit/autark/main/usecases/public/';

const db = new AutkSpatialDb();
await db.init();

await db.loadOsm({
    queryArea: { geocodeArea: 'New York', areas: ['Manhattan Island'] },
    outputTableName: 'table_osm',
    autoLoadLayers: {
        coordinateFormat: 'EPSG:3395',
        layers: ['surface', 'parks', 'water', 'roads', 'buildings'],
        dropOsmTable: true,
    },
});

await db.loadCustomLayer({
    geojsonFileUrl: `${URL}data/mnt_neighs.geojson`,
    outputTableName: 'neighborhoods',
    coordinateFormat: 'EPSG:3395',
});

for (const dataset of ['arrests', 'schools', 'restaurants', 'noise', 'trees', 'subways', 'newbuildings']) {
    await db.loadCsv({
        csvFileUrl: `${URL}data/${dataset}_manhattan_clean.csv`,
        outputTableName: dataset,
        geometryColumns: { latColumnName: 'latitude', longColumnName: 'longitude', coordinateFormat: 'EPSG:3395' },
    });
}

const layers = [];
for (const layer of db.getLayerTables()) {
    layers.push({ name: layer.name, type: layer.type, geojson: await db.getLayer(layer.name) });
}
return layers;

// Weighted livability score via ComputeGpgpu. The full sky-view-factor
// computation (autk-compute ComputeRender) lives upstream — paste it in
// when extending this example.

// 'arg' is the merged neighborhood GeoDataFrame, auto-wrapped as a layer
// array by the factory. Pull the FeatureCollection out.
const neighs = Array.isArray(arg) ? arg[0]?.geojson : arg;
if (!neighs) throw new Error('neighborhood collection missing');

const metrics = ['arrests', 'schools', 'restaurants', 'noise', 'trees', 'subways', 'newbuildings'];
const weights = [-1, 1, 1, -1, 1, 1, 1];

// Embed the per-neighborhood metric vector under a single property so the
// shader can read it as an attribute array.
for (const f of neighs.features) {
    f.properties.scoreInputs = metrics.map(m => Number(f.properties[m] ?? 0));
}

const scored = await new ComputeGpgpu().run({
    collection: neighs,
    variableMapping: { vals: 'scoreInputs' },
    attributeArrays: { vals: metrics.length },
    uniformArrays: { weights },
    resultField: 'score',
    wgslBody: `var s = 0.0; for (var i = 0u; i < vals_length; i++) { s += vals[i] * weights[i]; } return s;`,
});

return [{ name: 'neighborhoods', type: 'POLYGONS_2D', geojson: scored }];

// Render the OSM stack with neighborhoods colored by livability score.
const map = new AutkMap(container);
await map.init();
for (const layer of arg) {
    map.loadCollection(layer.name, { collection: layer.geojson, type: layer.type });
}
map.updateRenderInfo('neighborhoods', { opacity: 0.75, isPick: true, isColorMap: true });
map.updateThematic('neighborhoods', {
    collection: arg.find(l => l.name === 'neighborhoods').geojson,
    property: 'properties.compute.score',
});
map.draw();
return map;

// Parallel coordinates over all metrics; brush axes to highlight neighborhoods on the map.
const neighs = Array.isArray(arg) ? arg.find(l => l.name === 'neighborhoods')?.geojson : arg;
return new AutkChart(container, {
    type: 'parallel-coordinates',
    collection: neighs,
    attributes: { axis: ['arrests', 'schools', 'restaurants', 'noise', 'trees', 'subways', 'newbuildings', 'compute.score'] },
    labels: { axis: ['Arrests', 'Schools', 'Restaurants', 'Noise', 'Trees', 'Subways', 'New buildings', 'Score'], title: 'Livability metrics' },
    width: 790,
    events: ['brushY'],
});

// Table view of neighborhoods; click a row to highlight on the map.
const neighs = Array.isArray(arg) ? arg.find(l => l.name === 'neighborhoods')?.geojson : arg;
return new AutkChart(container, {
    type: 'table',
    collection: neighs,
    attributes: { axis: ['ntaname', 'arrests', 'schools', 'restaurants', 'noise', 'trees', 'subways', 'newbuildings', 'compute.score'] },
    labels: { axis: ['Neighborhood', 'Arrests', 'Schools', 'Restaurants', 'Noise', 'Trees', 'Subways', 'New', 'Score'], title: 'Manhattan livability table' },
    width: 790,
    events: ['click'],
});
